#include <bits/stdc++.h>
using namespace std;
int main() {
    string s; cin >> s;
    int n; cin >> n;
    unordered_set<string> wordDict;
    for (int i = 0; i < n; i++) {
        string word; cin >> word;
        wordDict.insert(word);
    }
    vector<bool> dp(s.size() + 1, false);
    dp[0] = true;
    for (int i = 1; i <= s.size(); i++) {
        for (int j = 0; j < i; j++) {
            if (dp[j] && wordDict.find(s.substr(j, i - j)) != wordDict.end()) {
                dp[i] = true;
                break;
            }
        }
    }
    cout << (dp.back() ? "true" : "false") << endl;
}
